function getMainVideoId()
{
	global $defaultLang, $country;

	switch ($defaultLang) {
		case 'en': return '1128168202';
		case 'es': return '1128158095';
		case 'it': return '1128160406';
		case 'pt': 
			if ($country == "BR") return '1164629750'; 
			return '1128160205';
		case 'th': return '1128159762';
		case 'fr': return '1128159997';
		case 'pl': return '1140335489';
		case 'nl': return '1142047322';
		case 'no': return '1142047375';
		case 'ro': return '1142047493';
		case 'de': return '1142047251';
		case 'cs': return '1142047623';
		case 'el': return '1142047059';
		case 'sv': return '1142047696';
		case 'zh': return '1142047126';
		case 'sk': return '1142047562';
		case 'ja': return '1142047764';
		case 'da': return '1149358497';
		case 'ko': return '1165574001';
		case 'hr': return '1164620881';

		default: return '1128168202';
	}
}

